// ParseRooms parses the room string (e.g., "101, 103~105") into a slice of room numbers.
func (p *ExcelParser) ParseRooms(cell string) ([]int, error) {
	if err := p.ValidateSpaces(cell); err != nil {
		return nil, err
	}

	cell = strings.ReplaceAll(cell, " ", "")
	if cell == "" {
		return nil, nil
	}

	parts := strings.Split(cell, ",")
	var rooms []int
	seen := make(map[int]bool)

	for _, part := range parts {
		if strings.Contains(part, "~") {
			rangeParts := strings.Split(part, "~")
			if len(rangeParts) != 2 {
				return nil, fmt.Errorf("invalid range format: %q", part)
			}

			start, err := strconv.Atoi(rangeParts[0])
			if err != nil {
				return nil, fmt.Errorf("invalid start room number: %q", rangeParts[0])
			}
			end, err := strconv.Atoi(rangeParts[1])
			if err != nil {
				return nil, fmt.Errorf("invalid end room number: %q", rangeParts[1])
			}

			if start >= end {
				return nil, fmt.Errorf("range must be ascending: %q", part)
			}

			for r := start; r <= end; r++ {
				// Skipping invalid rooms like 150-199 if user specified 149~201.
				// Wait, the spec says "指定するときは必ず昇順" and the valid rooms are 1F~9F, 01~49.
				// If they specify 149~201, it includes 150... which is invalid. 
				// The prompt says "部屋番号を ~ で指定するときは必ず昇順。"
				// Let's validate every generated room.
				if err := validateRoom(r); err != nil {
					return nil, err
				}
				if seen[r] {
					return nil, fmt.Errorf("duplicate room number: %d", r)
				}
				seen[r] = true
				rooms = append(rooms, r)
			}
		} else {
			r, err := strconv.Atoi(part)
			if err != nil {
				return nil, fmt.Errorf("invalid room number: %q", part)
			}
			if err := validateRoom(r); err != nil {
				return nil, err
			}
			if seen[r] {
				return nil, fmt.Errorf("duplicate room number: %d", r)
			}
			seen[r] = true
			rooms = append(rooms, r)
		}
	}
	return rooms, nil
}

func validateRoom(r int) error {
	floor := r / 100
	room := r % 100
	if floor < 1 || floor > 9 {
		return fmt.Errorf("invalid floor in room %d", r)
	}
	if room < 1 || room > 49 {
		return fmt.Errorf("invalid room number %d, must be between 01 and 49", r)
	}
	return nil
}

